import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import '../../styles/kuppi.css';

const API = 'http://localhost:5000/api/kuppi';

const Kuppi = () => {
    const { user } = useAuth();
    const [posts, setPosts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [sortBy, setSortBy] = useState('newest');
    const [showForm, setShowForm] = useState(false);
    const [commentText, setCommentText] = useState({});
    const [formData, setFormData] = useState({
        title: '', module: '', date: '', time: '', location: '', description: '', maxParticipants: ''
    });

    const fetchPosts = async () => {
        try {
            setLoading(true);
            const res = await axios.get(`${API}/posts`);
            setPosts(res.data.data || []);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to load kuppi posts');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchPosts();
    }, []);

    const createPost = async (e) => {
        e.preventDefault();
        try {
            await axios.post(`${API}/posts`, { ...formData, date: `${formData.date}T${formData.time || '12:00'}:00` });
            setFormData({ title: '', module: '', date: '', time: '', location: '', description: '', maxParticipants: '' });
            setShowForm(false);
            fetchPosts();
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to create post');
        }
    };

    const doAction = async (postId, action) => {
        try {
            await axios.post(`${API}/posts/${postId}/${action}`);
            fetchPosts();
        } catch (err) {
            setError(err.response?.data?.message || 'Action failed');
        }
    };

    const postComment = async (postId) => {
        const text = (commentText[postId] || '').trim();
        if (!text) return;
        try {
            await axios.post(`${API}/posts/${postId}/comments`, { text });
            setCommentText((prev) => ({ ...prev, [postId]: '' }));
            fetchPosts();
        } catch (err) {
            setError(err.response?.data?.message || 'Comment failed');
        }
    };

    const downloadApplicants = async (postId) => {
        try {
            const res = await axios.get(`${API}/posts/${postId}/applicants/export`, { responseType: 'blob' });
            const url = URL.createObjectURL(new Blob([res.data], { type: 'text/csv' }));
            const a = document.createElement('a');
            a.href = url;
            a.download = `kuppi-${postId}-applicants.csv`;
            a.click();
            URL.revokeObjectURL(url);
        } catch (err) {
            setError(err.response?.data?.message || 'Export failed');
        }
    };

    const sortedPosts = [...posts].sort((a, b) => {
        if (sortBy === 'newest') return new Date(b.createdAt) - new Date(a.createdAt);
        if (sortBy === 'likes') return (b.likes?.length || 0) - (a.likes?.length || 0);
        return new Date(a.date) - new Date(b.date);
    });

    return (
        <div className="kuppi-container">
            <div className="kuppi-header">
                <h1 className="kuppi-title">Kuppi Hub</h1>
                <button className="btn btn-primary create-btn" onClick={() => setShowForm((p) => !p)}>{showForm ? 'Cancel' : '+ Create Kuppi'}</button>
            </div>
            {error && <div className="alert alert-error">{error}</div>}
            {showForm && (
                <div className="create-post-card">
                    <form onSubmit={createPost}>
                        <input placeholder="Title" value={formData.title} onChange={(e) => setFormData({ ...formData, title: e.target.value })} />
                        <input placeholder="Module" value={formData.module} onChange={(e) => setFormData({ ...formData, module: e.target.value })} />
                        <input type="date" value={formData.date} onChange={(e) => setFormData({ ...formData, date: e.target.value })} />
                        <input type="time" value={formData.time} onChange={(e) => setFormData({ ...formData, time: e.target.value })} />
                        <input placeholder="Location" value={formData.location} onChange={(e) => setFormData({ ...formData, location: e.target.value })} />
                        <input type="number" placeholder="Max participants" value={formData.maxParticipants} onChange={(e) => setFormData({ ...formData, maxParticipants: e.target.value })} />
                        <textarea placeholder="Description" value={formData.description} onChange={(e) => setFormData({ ...formData, description: e.target.value })} />
                        <button className="btn btn-primary" type="submit">Post</button>
                    </form>
                </div>
            )}
            <div className="sorting-bar">
                <button className={`sort-btn ${sortBy === 'newest' ? 'active' : ''}`} onClick={() => setSortBy('newest')}>Newest</button>
                <button className={`sort-btn ${sortBy === 'likes' ? 'active' : ''}`} onClick={() => setSortBy('likes')}>Most Liked</button>
                <button className={`sort-btn ${sortBy === 'upcoming' ? 'active' : ''}`} onClick={() => setSortBy('upcoming')}>Upcoming</button>
            </div>
            {loading ? <div className="loading">Loading...</div> : (
                <div className="posts-grid">
                    {sortedPosts.map((post) => (
                        <div className="post-card" key={post._id}>
                            <h3>{post.title}</h3>
                            <div>{post.module} · {new Date(post.date).toLocaleString()}</div>
                            <p>{post.description}</p>
                            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                                <button className="btn btn-outline btn-sm" onClick={() => doAction(post._id, 'like')}>👍 {post.likes?.length || 0}</button>
                                <button className="btn btn-outline btn-sm" onClick={() => doAction(post._id, 'dislike')}>👎 {post.dislikes?.length || 0}</button>
                                <button className="btn btn-outline btn-sm" onClick={() => doAction(post._id, 'join')}>{post.userJoined ? 'Leave' : 'Apply / Join'} ({post.participants?.length || 0})</button>
                                {post.student?._id === user?.id && (
                                    <button className="btn btn-primary btn-sm" onClick={() => downloadApplicants(post._id)}>Download Applicants (Excel CSV)</button>
                                )}
                            </div>
                            <div style={{ marginTop: 10 }}>
                                {(post.comments || []).map((c) => (
                                    <div key={c._id} style={{ fontSize: 13 }}><strong>{c.user?.name || 'User'}:</strong> {c.text}</div>
                                ))}
                                <div style={{ display: 'flex', gap: 8, marginTop: 8 }}>
                                    <input style={{ flex: 1 }} placeholder="Write a comment..." value={commentText[post._id] || ''} onChange={(e) => setCommentText((prev) => ({ ...prev, [post._id]: e.target.value }))} />
                                    <button className="btn btn-sm btn-primary" onClick={() => postComment(post._id)}>Post</button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Kuppi;
